# Configuration from environment variables
SOURCE_BUCKET = os.environ.get('SOURCE_BUCKET')
RESULTS_BUCKET = os.environ.get('RESULTS_BUCKET')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN')

# Allowed image extensions and content types
ALLOWED_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.gif', '.bmp', '.webp', '.tiff'}
ALLOWED_CONTENT_TYPES = {
    'image/jpeg', 'image/png', 'image/gif', 'image/bmp', 'image/webp', 'image/tiff'
}
MAX_FILE_SIZE_BYTES = 50 * 1024 * 1024  # 50 MB limit

# Initialize clients outside handler for connection reuse
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')


def validate_bucket_name(bucket_name, expected_bucket):
    """Validate that the bucket name matches the expected configured bucket."""
    if bucket_name != expected_bucket:
        raise ValueError(
            f"Unexpected bucket: {bucket_name}. Expected: {expected_bucket}"
        )


def validate_object_key(key):
    """
    Validate the S3 object key to prevent path traversal and ensure
    it references an allowed image type.
    """
    # Decode the key
    decoded_key = unquote_plus(key)

    # Prevent path traversal
    if '..' in decoded_key or decoded_key.startswith('/'):
        raise ValueError(f"Invalid object key (path traversal attempt): {decoded_key}")

    # Normalize and check for null bytes
    if '\x00' in decoded_key:
        raise ValueError("Invalid object key (null byte detected)")

    # Validate file extension
    key_lower = decoded_key.lower()
    has_valid_extension = any(key_lower.endswith(ext) for ext in ALLOWED_EXTENSIONS)
    if not has_valid_extension:
        raise ValueError(
            f"Unsupported file type for key: {decoded_key}. "
            f"Allowed: {ALLOWED_EXTENSIONS}"
        )

    return decoded_key


def validate_content_type(content_type):
    """Validate that the content type is an allowed image type."""
    if content_type not in ALLOWED_CONTENT_TYPES:
        raise ValueError(
            f"Unsupported content type: {content_type}. "
            f"Allowed: {ALLOWED_CONTENT_TYPES}"
        )


def validate_file_size(content_length):
    """Validate that the file size is within acceptable limits."""
    if content_length > MAX_FILE_SIZE_BYTES:
        raise ValueError(
            f"File size {content_length} exceeds maximum allowed "
            f"size of {MAX_FILE_SIZE_BYTES} bytes"
        )


def sanitize_for_logging(value, max_length=200):
    """Sanitize a value for safe logging to prevent log injection."""
    if value is None:
        return "None"
    sanitized = str(value)[:max_length]
    # Remove newlines and control characters that could enable log injection
    sanitized = sanitized.replace('\n', '\\n').replace('\r', '\\r')
    sanitized = ''.join(
        char if (char.isprintable() or char == ' ') else '?' for char in sanitized
    )
    return sanitized


def get_s3_object_safely(bucket, key):
    """
    Retrieve an S3 object with validation of content type and size.
    Returns the S3 response object.
    """
    # First, do a HEAD request to check metadata without downloading
    head_response = s3_client.head_object(Bucket=bucket, Key=key)

    content_type = head_response.get('ContentType', '')
    content_length = head_response.get('ContentLength', 0)

    validate_content_type(content_type)
    validate_file_size(content_length)

    # Now retrieve the actual object
    response = s3_client.get_object(Bucket=bucket, Key=key)
    return response, content_type, content_length


