def write_results_to_s3(results, source_key):
    """Write processing results to the results S3 bucket."""
    # Generate a deterministic results key based on the source key
    results_key = f"results/{source_key}.json"

    # Validate the results key
    if '..' in results_key:
        raise ValueError("Invalid results key generated")

    s3_client.put_object(
        Bucket=RESULTS_BUCKET,
        Key=results_key,
        Body=json.dumps(results, default=str),
        ContentType='application/json',
        ServerSideEncryption='aws:kms'
    )

    logger.info(
        "Results written to S3",
        extra={
            'bucket': RESULTS_BUCKET,
            'key': sanitize_for_logging(results_key)
        }
    )
    return results_key


def send_notification(source_key, results_key, status, error_message=None):
    """Send an SNS notification about the processing result."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return

    message = {
        'source_key': source_key,
        'results_key': results_key,
        'status': status,
    }
    if error_message:
        # Truncate error message to prevent oversized SNS messages
        message['error'] = str(error_message)[:500]

    subject = f"Image Processing {status.capitalize()}: {source_key[:80]}"

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject,
            Message=json.dumps(message, default=str),
            MessageAttributes={
                'status': {
                    'DataType': 'String',
                    'StringValue': status
                }
            }
        )
        logger.info(
            "SNS notification sent",
            extra={'status': status, 'key': sanitize_for_logging(source_key)}
        )
    except ClientError as e:
        logger.error(
            "Failed to send SNS notification",
            extra={'error': str(e), 'key': sanitize_for_logging(source_key)}
        )


def lambda_handler(event, context):
    """
    AWS Lambda handler for processing images uploaded to S3.

    Triggered by S3 PUT events. Reads the image, processes it,
    writes results back to S3, and sends an SNS notification.
    """
    logger.info("Lambda invocation started", extra={
        'request_id': context.aws_request_id if context else 'unknown',
        'function_name': context.function_name if context else 'unknown'
    })

    # Validate environment configuration
    if not SOURCE_BUCKET or not RESULTS_BUCKET:
        logger.error("Missing required environment variables: SOURCE_BUCKET, RESULTS_BUCKET")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Lambda misconfigured'})
        }

    processed_records = []
    errors = []

    for record in event.get('Records', []):
        source_key = None
        try:
            # Extract S3 event information
            s3_event = record.get('s3', {})
            bucket_name = s3_event.get('bucket', {}).get('name', '')
            raw_key = s3_event.get('object', {}).get('key', '')

            # Validate the source bucket
            validate_bucket_name(bucket_name, SOURCE_BUCKET)

            # Validate and sanitize the object key
            source_key = validate_object_key(raw_key)

            logger.info(
                "Processing image",
                extra={
                    'bucket': sanitize_for_logging(bucket_name),
                    'key': sanitize_for_logging(source_key)
                }
            )

            # Retrieve the image with validation
            s3_response, content_type, content_length = get_s3_object_safely(
                bucket_name, source_key
            )

            # Read image data
            image_data = s3_response['Body'].read()

            # Verify actual size matches reported size (defense in depth)
            if len(image_data) > MAX_FILE_SIZE_BYTES:
                raise ValueError(
                    f"Actual file size {len(image_data)} exceeds limit"
                )

            # Process the image
            results = process_image(image_data, source_key, content_type)

            # Write results to S3
            results_key = write_results_to_s3(results, source_key)

            # Send success notification
            send_notification(source_key, results_key, 'success')

            processed_records.append({
                'key': source_key,
                'status': 'success',
                'results_key': results_key
            })

            logger.info(
                "Image processed successfully",
                extra={'key': sanitize_for_logging(source_key)}
            )

        except ValueError as e:
            # Validation errors - log and notify but don't retry
            safe_key = sanitize_for_logging(source_key or raw_key)
            logger.warning(
                "Validation error processing image",
                extra={'key': safe_key, 'error': str(e)}
            )
            send_notification(
                source_key or 'unknown', None, 'validation_error', str(e)
            )
            errors.append({
                'key': source_key or 'unknown',
                'error': str(e),
                'retryable': False
            })

        except ClientError as e:
            # AWS service errors - may be retryable
            error_code = e.response.get('Error', {}).get('Code', 'Unknown')
            safe_key = sanitize_for_logging(source_key or 'unknown')
            logger.error(
                "AWS service error processing image",
                extra={
                    'key': safe_key,
                    'error_code': error_code,
                    'error': str(e)
                }
            )
            send_notification(
                source_key or 'unknown', None, 'error', str(e)
            )

            # Re-raise for retryable errors so Lambda retries
            if error_code in ('InternalError', 'ServiceUnavailable', 'SlowDown'):
                raise

            errors.append({
                'key': source_key or 'unknown',
                'error': str(e),
                'retryable': False
            })

        except Exception as e:
            # Unexpected errors - log securely without leaking internals
            safe_key = sanitize_for_logging(source_key or 'unknown')
            logger.error(
                "Unexpected error processing image",
                extra={
                    'key': safe_key,
                    'error_type': type(e).__name__,
                    'error': str(e)
                },
                exc_info=True
            )
            send_notification(
                source_key or 'unknown', None, 'error',
                'An unexpected error occurred during processing'
            )
            errors.append({
                'key': source_key or 'unknown',
                'error': 'Internal processing error',
                'retryable': False
            })

    response = {
        'statusCode': 200 if not errors else 207,
        'body': json.dumps({
            'processed': len(processed_records),
            'errors': len(errors),
            'results': processed_records,
            'error_details': errors
        })
    }

    logger.info(
        "Lambda invocation complete",
        extra={
            'processed_count': len(processed_records),
            'error_count': len(errors)
        }
    )

    return response